external_knowledge:
- 'journey tickets' refers to the transportation requests;
- 'riding the wave of anticipation' metaphorically describes requests with a status of 'pending';
- 'destinations on the horizon' refers to the target locations of these requests.

sql:
SELECT assigned_vehicle_id, COUNT(*) AS total_requests
FROM transport_requests
GROUP BY assigned_vehicle_id;

SELECT COUNT(request_id) AS NumberOfRequests
FROM transport_requests
WHERE source_id = 100 AND created_at >= date('now','-30 days');

SELECT COUNT(*)
FROM transport_requests
WHERE status = 'delivered';

SELECT COUNT(*) AS total_requests, SUM(r.total_distance) AS total_distance
FROM transport_requests tr
INNER JOIN routes r ON tr.request_id = r.request_id;

SELECT COUNT(DISTINCT assigned_vehicle_id) 
FROM transport_requests 
WHERE status <> 'pending';

SELECT * 
FROM routes 
WHERE route_status = 'completed';

SELECT route_id, COUNT(route_event_id) AS total_events
FROM route_events
GROUP BY route_id;

SELECT AVG(fuel_cost) AS "Average Fuel Cost Per Route", route_id
FROM route_costs
GROUP BY route_id;

